node -e "
const { chromium } = require('playwright');
const fs = require('fs');

(async () => {
  const cookies = JSON.parse(fs.readFileSync('tapd_cookies.json', 'utf8'));

  const browser = await chromium.launch({ headless: false });
  const context = await browser.newContext();
  await context.addCookies(cookies);
  const page = await context.newPage();

  await page.goto('https://www.tapd.cn/31253609/prong/stories/add?workitem_type_id=1131253609001000049');
  await page.waitForLoadState('networkidle');
  await page.waitForTimeout(2000);

  // 点击展开预设子工作项
  const editLink = page.locator('.j-edit-preset-stories, .edit-workitems-relation').first();
  if (await editLink.count() > 0) {
    await editLink.click();
    await page.waitForTimeout(2000);
  }

  // 截图
  await page.screenshot({ path: 'tapd_ccg_story2.png', fullPage: true });

  // 抓 preset 子工作项列表
  const presetData = await page.evaluate(() => {
    // 尝试找 preset story 列表
    const results = [];

    // 找所有包含子工作项名称的元素
    const storyItems = document.querySelectorAll('.preset-story-item, .story-item, .sub-story-item, .j-preset-story-item');
    storyItems.forEach((el, i) => {
      results.push({ type: 'story-item', index: i, text: el.textContent?.trim().substring(0, 300) });
    });

    // 找 modal/popup 里的内容
    const modals = document.querySelectorAll('.modal-body, .dialog-body, .popup-body, .layer-content');
    modals.forEach((el, i) => {
      if (el.offsetParent !== null) { // visible
        results.push({ type: 'modal', index: i, html: el.innerHTML?.substring(0, 2000) });
      }
    });

    // 找所有 tr 或 li 包含「子工作项」相关内容
    const rows = document.querySelectorAll('tr, li');
    rows.forEach((el, i) => {
      const text = el.textContent?.trim();
      if (text && text.length < 300 && (text.includes('客户端') || text.includes('策划') || text.includes('QA') || text.includes('服务端') || text.includes('UI') || text.includes('动效') || text.includes('音频'))) {
        results.push({ type: 'row', index: i, class: el.className, text: text.substring(0, 200) });
      }
    });

    return results;
  });
  console.log('Preset data:', JSON.stringify(presetData, null, 2));

  // 直接获取 preset stories 的 JS 变量
  const jsData = await page.evaluate(() => {
    // TAPD 通常把配置存在全局变量里
    const keys = Object.keys(window).filter(k => k.toLowerCase().includes('preset') || k.toLowerCase().includes('story') || k.toLowerCase().includes('sub'));
    return keys.slice(0, 20);
  });
  console.log('Global JS keys with preset/story/sub:', JSON.stringify(jsData));

  await browser.close();
})();
"

