const { chromium } = require('playwright');
const fs = require('fs');

(async () => {
  const cookies = JSON.parse(fs.readFileSync('tapd_cookies.json', 'utf8'));

  const browser = await chromium.launch({ headless: false });
  const context = await browser.newContext();
  await context.addCookies(cookies);
  const page = await context.newPage();

  await page.goto('https://www.tapd.cn/31253609/prong/stories/add?workitem_type_id=1131253609001000049');
  await page.waitForLoadState('networkidle');
  await page.waitForTimeout(2000);

  // 拦截 XHR 获取预设子工作项数据
  page.on('response', async (response) => {
    const url = response.url();
    if (url.includes('preset') || url.includes('sub_story') || url.includes('workitem_type')) {
      try {
        const text = await response.text();
        console.log('XHR URL:', url);
        console.log('XHR Response:', text.substring(0, 2000));
      } catch(e) {}
    }
  });

  // 点击编辑预设子工作项图标
  await page.click('.j-edit-preset-stories');
  await page.waitForTimeout(4000);

  // 截图
  await page.screenshot({ path: 'tapd_after_click.png', fullPage: true });

  // 查找所有可见的 layer/popup
  const layers = await page.evaluate(() => {
    const results = [];
    const all = document.querySelectorAll('*');
    for (const el of all) {
      const style = window.getComputedStyle(el);
      if (style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0') {
        const cls = el.className || '';
        if (typeof cls === 'string' && (cls.includes('layer') || cls.includes('layui') || cls.includes('popup') || cls.includes('dialog') || cls.includes('modal'))) {
          const text = el.textContent?.trim();
          if (text && text.length > 10 && text.length < 5000) {
            results.push({ tag: el.tagName, class: cls.substring(0, 100), text: text.substring(0, 500) });
          }
        }
      }
    }
    return results.slice(0, 20);
  });
  console.log('Visible layers/popups:', JSON.stringify(layers, null, 2));

  // 找隐藏的 input 中的子工作项数据
  const hiddenInputs = await page.evaluate(() => {
    const inputs = document.querySelectorAll('input[type=hidden]');
    const results = [];
    inputs.forEach(inp => {
      if (inp.name && inp.value && inp.value.length > 10) {
        results.push({ name: inp.name, value: inp.value.substring(0, 500) });
      }
    });
    return results;
  });
  console.log('Hidden inputs:', JSON.stringify(hiddenInputs, null, 2));

  await browser.close();
})();
"

