const { chromium } = require('playwright');
const fs = require('fs');

(async () => {
  // Load cookies
  const cookies = JSON.parse(fs.readFileSync('tapd_cookies.json', 'utf8'));

  const browser = await chromium.launch({ headless: false });
  const context = await browser.newContext();
  await context.addCookies(cookies);
  const page = await context.newPage();

  await page.goto('https://www.tapd.cn/31253609/prong/stories/add?workitem_type_id=1131253609001000049');
  await page.waitForLoadState('networkidle');

  // 截图
  await page.screenshot({ path: 'tapd_ccg_story.png', fullPage: true });
  console.log('Screenshot saved');

  // 分析预设子工作项
  const subItems = await page.evaluate(() => {
    const items = [];
    // 找子工作项相关元素
    const checkboxes = document.querySelectorAll('.sub-workitem input[type=checkbox], .preset-sub-workitem input[type=checkbox], input[name*=sub], input[id*=sub]');
    checkboxes.forEach((cb, i) => {
      items.push({
        index: i,
        id: cb.id,
        name: cb.name,
        value: cb.value,
        checked: cb.checked,
        label: cb.closest('label')?.textContent?.trim() || cb.parentElement?.textContent?.trim()
      });
    });
    return items;
  });
  console.log('SubItems checkboxes:', JSON.stringify(subItems, null, 2));

  // 再找所有子工作项文字
  const subTexts = await page.evaluate(() => {
    const results = [];
    // 找包含「子工作项」的区域
    const allText = document.querySelectorAll('[class*=sub], [id*=sub], [class*=child], [class*=preset]');
    allText.forEach(el => {
      if (el.children.length < 10) {
        results.push({ tag: el.tagName, class: el.className, id: el.id, text: el.textContent?.trim().substring(0, 200) });
      }
    });
    return results;
  });
  console.log('Sub elements:', JSON.stringify(subTexts.slice(0, 30), null, 2));

  await browser.close();
})();
"

