(async () => {
  const cookies = JSON.parse(fs.readFileSync('tapd_cookies.json', 'utf8'));
  const browser = await chromium.launch({ headless: false });
  const context = await browser.newContext();
  await context.addCookies(cookies);
  const page = await context.newPage();

  // 拦截所有 preset 相关的 API
  page.on('request', req => {
    if (req.url().includes('preset') || req.url().includes('template')) {
      console.log('REQ:', req.method(), req.url());
    }
  });
  page.on('response', async resp => {
    if (resp.url().includes('preset') || (resp.url().includes('template') && !resp.url().includes('.js') && !resp.url().includes('.css'))) {
      console.log('RESP:', resp.status(), resp.url());
    }
  });

  // 进入 CCG 玩法模板的创建页，点击编辑预设子工作项
  await page.goto('https://www.tapd.cn/31253609/prong/stories/add?workitem_type_id=1131253609001000049');
  await page.waitForLoadState('networkidle');
  await page.waitForTimeout(2000);

  // 点击编辑铅笔图标
  await page.click('.j-edit-preset-stories');
  await page.waitForTimeout(4000);

  await page.screenshot({ path: 'tapd_preset_edit_modal.png', fullPage: true });

  // 找 modal
  const modalHtml = await page.evaluate(() => {
    // 找所有 layer/弹层
    const layers = document.querySelectorAll('[id^=layui-layer], .layui-layer, [class*=layer-page]');
    let html = '';
    layers.forEach(l => { if (l.offsetParent !== null) html += l.outerHTML?.substring(0, 3000); });
    return html || 'no visible layers';
  });
  console.log('Modal HTML:', modalHtml.substring(0, 3000));

  await browser.close();
})();
