  const browser = await chromium.launch({ headless: false });
  const context = await browser.newContext();
  await context.addCookies(cookies);
  const page = await context.newPage();

  // 拦截 save_preset 相关的接口
  page.on('request', req => {
    if (req.url().includes('preset') || req.url().includes('save')) {
      const postData = req.postData();
      console.log('REQ:', req.method(), req.url(), postData ? postData.substring(0, 500) : '');
    }
  });

  await page.goto('https://www.tapd.cn/31253609/prong/stories/add?workitem_type_id=1131253609001000049');
  await page.waitForLoadState('networkidle');
  await page.waitForTimeout(2000);

  // 点击编辑预设子工作项
  await page.click('.j-edit-preset-stories');
  await page.waitForTimeout(3000);

  // 看看点击后页面变化 - 找 iframe 或新窗口
  const frames = page.frames();
  console.log('Frames count:', frames.length);
  frames.forEach((f, i) => console.log('Frame', i, f.url()));

  // 找所有可见元素
  const visibleNew = await page.evaluate(() => {
    const results = [];
    document.querySelectorAll('*').forEach(el => {
      const style = window.getComputedStyle(el);
      if (style.position === 'fixed' || style.position === 'absolute') {
        if (el.offsetWidth > 200 && el.offsetHeight > 100) {
          const text = el.innerText?.trim()?.substring(0, 200);
          if (text) results.push({ tag: el.tagName, class: el.className?.substring(0,80), text });
        }
      }
    });
    return results.slice(0, 10);
  });
  console.log('Fixed/Absolute elements:', JSON.stringify(visibleNew, null, 2));

  await page.screenshot({ path: 'tapd_after_edit_click.png', fullPage: false });
  console.log('Screenshot saved');

  await browser.close();
})();
