  page.on('request', req => {
    if (req.url().includes('preset') || req.url().includes('template')) {
      console.log('REQ:', req.method(), req.url());
    }
  });
  page.on('response', async resp => {
    if (resp.url().includes('preset') || (resp.url().includes('template') && !resp.url().includes('.js') && !resp.url().includes('.css'))) {
      console.log('RESP:', resp.status(), resp.url());
