  page.on('request', req => {
    if (req.url().includes('preset') || req.url().includes('save')) {
      const postData = req.postData();
      console.log('REQ:', req.method(), req.url(), postData ? postData.substring(0, 500) : '');
    }
  });

  await page.goto('https://www.tapd.cn/31253609/prong/stories/add?workitem_type_id=1131253609001000049');
