  // 点击编辑预设子工作项
  await page.click('.j-edit-preset-stories');
  await page.waitForTimeout(3000);

  // 看看点击后页面变化 - 找 iframe 或新窗口
  const frames = page.frames();
  console.log('Frames count:', frames.length);
  frames.forEach((f, i) => console.log('Frame', i, f.url()));

  // 找所有可见元素
  const visibleNew = await page.evaluate(() => {
    const results = [];
    document.querySelectorAll('*').forEach(el => {
      const style = window.getComputedStyle(el);
      if (style.position === 'fixed' || style.position === 'absolute') {
        if (el.offsetWidth > 200 && el.offsetHeight > 100) {
          const text = el.innerText?.trim()?.substring(0, 200);
          if (text) results.push({ tag: el.tagName, class: el.className?.substring(0,80), text });
        }
      }
    });
    return results.slice(0, 10);
  });
