      const style = window.getComputedStyle(el);
      if (style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0') {
        const cls = el.className || '';
        if (typeof cls === 'string' && (cls.includes('layer') || cls.includes('layui') || cls.includes('popup') || cls.includes('dialog') || cls.includes('modal'))) {
          const text = el.textContent?.trim();
          if (text && text.length > 10 && text.length < 5000) {
            results.push({ tag: el.tagName, class: cls.substring(0, 100), text: text.substring(0, 500) });
          }
        }
      }
    }
    return results.slice(0, 20);
  });
  console.log('Visible layers/popups:', JSON.stringify(layers, null, 2));

  // 找隐藏的 input 中的子工作项数据
  const hiddenInputs = await page.evaluate(() => {
    const inputs = document.querySelectorAll('input[type=hidden]');
    const results = [];
    inputs.forEach(inp => {
      if (inp.name && inp.value && inp.value.length > 10) {
        results.push({ name: inp.name, value: inp.value.substring(0, 500) });
      }
    });
    return results;
  });
  console.log('Hidden inputs:', JSON.stringify(hiddenInputs, null, 2));

  await browser.close();
})();
